45:     public static Builder builder(ProduceRequestData data, boolean useTransactionV1Version) {
46:         // When we use transaction V1 protocol in transaction we set the request version upper limit to
47:         // LAST_STABLE_VERSION_BEFORE_TRANSACTION_V2 so that the broker knows that we're using transaction protocol V1.
48:         short maxVersion = useTransactionV1Version ?
49:             LAST_STABLE_VERSION_BEFORE_TRANSACTION_V2 : ApiKeys.PRODUCE.latestVersion();
50:         return new Builder(ApiKeys.PRODUCE.oldestVersion(), maxVersion, data);
