57:     public static class Builder extends AbstractRequest.Builder<ProduceRequest> {
58:         private final ProduceRequestData data;
59: 
60:         public Builder(short minVersion,
61:                        short maxVersion,
62:                        ProduceRequestData data) {
63:             super(ApiKeys.PRODUCE, minVersion, maxVersion);
64:             this.data = data;
65:         }
66: 
67:         @Override
68:         public ProduceRequest build(short version) {
69:             // Validate the given records first
70:             data.topicData().forEach(tpd ->
71:                 tpd.partitionData().forEach(partitionProduceData ->
72:                     ProduceRequest.validateRecords(version, partitionProduceData.records())));
73:             return new ProduceRequest(data, version);
74:         }
