78:             return "(type=ProduceRequest" +
79:                     ", acks=" + data.acks() +
80:                     ", timeout=" + data.timeoutMs() +
81:                     ", partitionRecords=(" + data.topicData().stream().flatMap(d -> d.partitionData().stream()).collect(Collectors.toList()) +
82:                     "), transactionalId='" + (data.transactionalId() != null ? data.transactionalId() : "") +
83:                     "'";
