115:                     Map<TopicIdPartition, Integer> tmpPartitionSizes = new HashMap<>();
116:                     data.topicData().forEach(topicData ->
117:                         topicData.partitionData().forEach(partitionData ->
118:                             // While topic id and name might not be populated at the same time in the request all the time;
119:                             // for example on server side they will never be populated together while in produce client they will be,
120:                             // to simplify initializing `TopicIdPartition` the code will use both topic name and id.
